## 4. 性能优化

### 4.1 节点池

```typescript
import { _decorator, Component, Node, Prefab, instantiate } from 'cc';

@ccclass('ObjectPool')
export class ObjectPool extends Component {
    private pool: Node[] = [];

    @property(Prefab)
    prefab: Prefab = null;

    get(): Node {
        if (this.pool.length > 0) {
            const node = this.pool.pop()!;
            node.active = true;
            return node;
        }
        return instantiate(this.prefab);
    }

    put(node: Node) {
        node.active = false;
        this.pool.push(node);
    }
}
```

