            console.log('认证失败');
            return '认证失败';
        }
        console.log('认证通过');
        return super.handle(request);
    }
}

class ValidationHandler extends Handler {
    handle(request) {
        if (!request.data) {
            console.log('数据验证失败');
            return '数据验证失败';
        }
        console.log('数据验证通过');
        return super.handle(request);
    }
}

class ProcessHandler extends Handler {
    handle(request) {
        console.log('处理请求');
        return '处理完成';
    }
}

// 使用
